fixed_code:
extern crate libc;
use libc::c_int;

#[link(name = "example")]
extern "C" {
    fn get_value() -> Option<c_int>;
}

fn main() {
    match unsafe { get_value() } {
        Some(value) => println!("Value: {}
", value),
        None => println!("No value returned.")
    }
}
